const data = msg.payload[0];
const dist = data.distance;

const sensorHeight = 35; // cm above rim
const binDepth = 75;     // cm depth
const maxDist = sensorHeight + binDepth; // 110 cm

let status = "UNKNOWN";
let filledPct = 0;

// 1. Validate FIRST
if (dist === null || dist > maxDist) {
    status = "EMPTY";
    filledPct = 0;

} else if (dist < 12 || isNaN(dist)) {
    // lid closed / invalid reading
    status = "UNKNOWN";
    filledPct = 0;

} else {

    // 2. Calculate percentage (still useful for display)
    filledPct = ((maxDist - dist) / binDepth) * 100;
    filledPct = Math.max(0, Math.min(100, filledPct));

    // 3. Use DISTANCE-BASED thresholds (more reliable)
    if (dist >= 80) {
        // Far from trash → mostly empty
        status = "EMPTY";

    } else if (dist >= 60) {
        // Around ~70% but may already be emptied
        status = "NORMAL";

    } else if (dist >= 45) {
        // Mid-high level
        status = "ALMOST FULL";

    } else {
        // 40–50 cm or less → FULL (your requirement)
        status = "FULL";
    }
}

// Time calculation
const now = new Date();
const activityTime = new Date(data.last_activity);
const diffMin = Math.floor((now - activityTime) / 60000);

// 4. Format response
msg.payload = {
    binId: "checkbin_02",
    status: status,
    percent: Math.round(filledPct),
    displayStatus: `(${Math.round(filledPct)}% Full)`,
    rawDistance: dist != null ? `${dist.toFixed(1)} cm` : "N/A",
    lastActivity: diffMin,
    weather: `${data.temp}°C, ${data.humidity}% humidity`
};

return msg;

// Initialize a 24-hour grid for the dates found in the data
const heatmapData = {};
const days = [...new Set(msg.payload.map(item => item.date_label))];

// Create the structure: { hour: { date1: count, date2: count } }
for (let h = 0; h < 24; h++) {
    heatmapData[h] = {};
    days.forEach(day => {
        heatmapData[h][day] = { count: 0, rain: 0 };
    });
}

// Fill the grid with actual data
msg.payload.forEach(row => {
    const hour = row.hour_of_day;
    const day = row.date_label;
    heatmapData[hour][day] = {
        count: row.activity_count,
        isRainy: row.rain_mm > 0 || row.weather_code >= 3 // Adjust code based on your API
    };
});

msg.payload = {
    labels: days, // Columns: ["2026-04-17", "2026-04-18"]
    data: heatmapData // Rows 0-23
};

return msg;

const rawData = msg.payload;
const processedData = [];

const sensorHeight = 35; 
const binDepth = 75;     
const maxDist = sensorHeight + binDepth; 

let prevDist = null;

rawData.forEach(row => {
    const dist = row.distance;
    let status = "UNKNOWN";
    let filledPct = 0;
    let event = null;

    // 1. User's Validation Logic
    if (dist === null || dist > maxDist) {
        status = "EMPTY";
        filledPct = 0;
    } else if (dist < 12 || isNaN(dist)) {
        status = "UNKNOWN"; // Lid closed / invalid
        filledPct = 0;
    } else {
        // Calculate Percentage
        filledPct = ((maxDist - dist) / binDepth) * 100;
        filledPct = Math.max(0, Math.min(100, filledPct));

        // Distance Thresholds
        if (dist >= 80) status = "EMPTY";
        else if (dist >= 60) status = "NORMAL";
        else if (dist >= 45) status = "ALMOST FULL";
        else status = "FULL";
    }

    // 2. Detect Emptying Event (Sudden jump in distance)
    // If the distance suddenly increases by more than 40cm, someone emptied it.
    if (prevDist !== null && dist - prevDist > 40 && dist >= 80) {
        event = "Emptied";
    }
    prevDist = dist;

    // Format time for frontend (e.g., "14:30")
    const dateObj = new Date(row.time);
    const timeString = dateObj.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });

    processedData.push({
        time: timeString,
        fullDate: row.time,
        distance: dist,
        filledPct: Math.round(filledPct),
        status: status,
        activity: row.activity_count,
        event: event
    });
});

msg.payload = processedData;
return msg;

const data = msg.payload;

// Helper function for Pearson Correlation
function getCorrelation(x, y) {
    const n = x.length;
    if (n === 0) return 0;
    const sumX = x.reduce((a, b) => a + b, 0);
    const sumY = y.reduce((a, b) => a + b, 0);
    const sumXY = x.reduce((a, b, i) => a + b * y[i], 0);
    const sumX2 = x.reduce((a, b) => a + b * b, 0);
    const sumY2 = y.reduce((a, b) => a + b * b, 0);

    const num = (n * sumXY) - (sumX * sumY);
    const den = Math.sqrt((n * sumX2 - sumX * sumX) * (n * sumY2 - sumY * sumY));
    return den === 0 ? 0 : (num / den).toFixed(2);
}

const activityArr = data.map(d => d.activity_count);
const humidityArr = data.map(d => d.humidity_pct);
const rainArr = data.map(d => d.precipitation_mm);

msg.payload = {
    correlation: {
        humidity: getCorrelation(activityArr, humidityArr),
        rain: getCorrelation(activityArr, rainArr)
    },
    timeline: data.map(d => ({
        time: new Date(d.hour_label).getHours() + ":00",
        activity: d.activity_count,
        humidity: d.humidity_pct,
        rain: d.precipitation_mm
    }))
};

return msg;

if (!msg.payload || msg.payload.length < 2) return null;

const sensorStats = msg.payload[0][0]; 
const surveyStats = msg.payload[1][0]; 

// 1. Reality Calculation:
// We only count readings between 12cm and 45cm as "Full".
// Values < 12 (Lid Closed) are ignored from the numerator.
const realityPct = Math.round((sensorStats.full_readings / sensorStats.total_readings) * 100);

// 2. Perception Calculation:
const perceptionPct = Math.round((surveyStats.overflow_reports / surveyStats.total_users) * 100);

// 3. The Gap Logic:
const gap = perceptionPct - realityPct;

msg.payload = {
    summary: {
        realityScore: realityPct,
        perceptionScore: perceptionPct,
        satisfaction: parseFloat(surveyStats.avg_satisfaction || 0).toFixed(1),
        totalResponses: surveyStats.total_users
    },
    narrative: {
        title: "Perception vs. Reality Gap",
        value: gap,
        analysis: gap > 0 
            ? `Users think the bin is full ${gap}% more often than sensor data shows. (Note: Lid-closed events are filtered).` 
            : `The bin stays full ${Math.abs(gap)}% more than users report.`
    }
};

return msg;

// ── Query Builder: fill prediction ──────────────────────────────
const binId = msg.req.params.bin_id || msg.req.query.bin_id || 'checkbin_02';

msg.binId = binId;

msg.topic = `
    SELECT distance_cm, recorded_at
    FROM fill_readings
    WHERE bin_id = ?
      AND distance_cm IS NOT NULL
    ORDER BY recorded_at DESC
    LIMIT 72
`;
// NOTE: removed the >= 12 filter here — we need raw data to detect post-emptying state

msg.payload = [binId];

return msg;

// ════════════════════════════════════════════════════════════════
// Controller: fill prediction
// Handles all post-emptying states:
//   - dist > 110 or null  → EMPTY (sensor out of range)
//   - dist ~90            → EMPTY (bag bloat / bumps after emptying)
//   - dist < 12           → UNKNOWN (lid closed or bag placed nearby)
//   - normal fill range   → categorize normally
// ════════════════════════════════════════════════════════════════

// ── Constants ────────────────────────────────────────────────────
const SENSOR_HEIGHT = 35;   // cm, sensor mounted above rim
const BIN_DEPTH = 75;   // cm, total bin depth
const MAX_DIST = SENSOR_HEIGHT + BIN_DEPTH; // 110 cm

const LID_ON_MAX_CM = 12;   // below this → lid closed or bag blocking sensor
const EMPTY_MIN_CM = 80;   // above this → bin is empty
const CLEANER_THRESHOLD_CM = 60;   // cleaner typically acts here (~70% fill)
const EMPTYING_DELTA_CM = 40;   // sudden jump larger than this = emptying event
const BAG_BLOAT_RANGE_MIN = 80;   // after emptying, bag can sit at 80–95 cm
const BAG_BLOAT_RANGE_MAX = 110;  //   (sensor still reads it but bin is empty)

// ── Helper: categorize a single distance reading ─────────────────
function categorize(dist) {
    if (dist === null || dist === undefined || isNaN(dist) || dist > MAX_DIST) {
        return { status: "EMPTY", filledPct: 0 };
    }
    if (dist < LID_ON_MAX_CM) {
        return { status: "UNKNOWN", filledPct: 0 };
    }

    let filledPct = ((MAX_DIST - dist) / BIN_DEPTH) * 100;
    filledPct = Math.round(Math.max(0, Math.min(100, filledPct)) * 10) / 10;

    let status;
    if (dist >= 80) status = "EMPTY";
    else if (dist >= 60) status = "NORMAL";
    else if (dist >= 45) status = "ALMOST FULL";
    else status = "FULL";

    return { status, filledPct };
}

// ── Helper: detect emptying events ───────────────────────────────
// readings = newest-first from DB
// Returns array of events, each with index into the ordered (oldest-first) array
function detectEmptyingEvents(orderedReadings) {
    const events = [];
    for (let i = 1; i < orderedReadings.length; i++) {
        const prev = parseFloat(orderedReadings[i - 1].distance_cm);
        const curr = parseFloat(orderedReadings[i].distance_cm);

        // Handle out-of-range as "very far" = 250 for delta calculation
        const prevDist = isNaN(prev) || prev > MAX_DIST ? 250 : prev;
        const currDist = isNaN(curr) || curr > MAX_DIST ? 250 : curr;

        const delta = currDist - prevDist; // positive = distance increased = trash removed

        if (delta > EMPTYING_DELTA_CM) {
            events.push({
                event: "emptying_detected",
                at: orderedReadings[i].recorded_at,
                before_cm: prevDist > 200 ? null : prevDist,
                after_cm: currDist > 200 ? null : currDist,
                delta_cm: Math.round(delta * 10) / 10,
                index: i   // position in orderedReadings — used to split cycles
            });
        }
    }
    return events;
}

// ── Helper: determine if current state is post-emptying ──────────
// After emptying, bin can read: null / >110 / 80-110 (bag bloat) / <12 (lid/bag nearby)
// Strategy: if the most recent emptying event is recent AND current dist is
//           in the "freshly emptied" range, treat as post-emptying.
function isPostEmptyingState(dist, emptyingEvents, orderedReadings) {
    if (emptyingEvents.length === 0) return false;

    const lastEvent = emptyingEvents[emptyingEvents.length - 1];
    const lastEventIndex = lastEvent.index;
    const totalReadings = orderedReadings.length;

    // How many readings have occurred since the last emptying event?
    const readingsSinceEmpty = totalReadings - 1 - lastEventIndex;

    // If emptying happened within the last 24 hours of readings AND
    // current dist suggests empty/near-empty/obstructed state
    const distIsEmpty = dist === null || isNaN(dist) || dist > MAX_DIST;
    const distIsBagBloat = dist >= BAG_BLOAT_RANGE_MIN && dist <= BAG_BLOAT_RANGE_MAX;
    const distIsLidOrBag = dist < LID_ON_MAX_CM;

    if ((distIsEmpty || distIsBagBloat || distIsLidOrBag) && readingsSinceEmpty <= 144) {
        // 144 readings = 24 hours at 10-min intervals
        return true;
    }

    return false;
}

// ── Helper: linear regression ─────────────────────────────────────
// points = [{ x: hoursElapsed, y: distance_cm }, ...]
function linearRegression(points) {
    const n = points.length;
    if (n < 2) return null;

    let sumX = 0, sumY = 0, sumXY = 0, sumXX = 0;
    for (const { x, y } of points) {
        sumX += x;
        sumY += y;
        sumXY += x * y;
        sumXX += x * x;
    }

    const denom = (n * sumXX - sumX * sumX);
    if (Math.abs(denom) < 1e-9) return null;

    const slope = (n * sumXY - sumX * sumY) / denom;
    const intercept = (sumY - slope * sumX) / n;

    // R² for confidence
    const yMean = sumY / n;
    let ssTot = 0, ssRes = 0;
    for (const { x, y } of points) {
        ssTot += (y - yMean) ** 2;
        ssRes += (y - (slope * x + intercept)) ** 2;
    }
    const r2 = ssTot < 1e-9 ? 0 : 1 - ssRes / ssTot;

    return { slope, intercept, r2 };
}

// ── Helper: build prediction from regression ──────────────────────
function buildPrediction(regression, t0, dataPointCount) {
    if (!regression) return null;

    const { slope, intercept, r2 } = regression;
    const isFilling = slope < -0.01;

    if (!isFilling) {
        return {
            fill_rate_cm_per_hour: Math.round(slope * 1000) / 1000,
            note: slope >= 0
                ? "Bin is not filling — distance stable or increasing."
                : "Fill rate too slow to make a meaningful prediction."
        };
    }

    // Time from t0 (oldest point) when dist hits CLEANER_THRESHOLD_CM
    const hoursFromStart = (CLEANER_THRESHOLD_CM - intercept) / slope;
    const nowOffsetHours = (Date.now() - t0) / 3600000;
    const hoursFromNow = hoursFromStart - nowOffsetHours;

    // Build projection points for chart (hourly for next 24h)
    const projectionHours = Math.min(24, Math.ceil(Math.abs(hoursFromNow)) + 2);
    const projectionPoints = [];
    for (let h = 0; h <= projectionHours; h++) {
        const futureHours = nowOffsetHours + h;
        const projDist = slope * futureHours + intercept;
        const clampedDist = Math.max(0, Math.min(MAX_DIST, projDist));
        projectionPoints.push({
            offset_hours: h,
            timestamp: new Date(Date.now() + h * 3600000).toISOString(),
            distance_cm: Math.round(clampedDist * 10) / 10,
            ...categorize(clampedDist)
        });
    }

    const confidence = r2 >= 0.85 ? "high"
        : r2 >= 0.5 ? "moderate"
            : "low";

    if (hoursFromNow <= 0) {
        return {
            threshold_cm: CLEANER_THRESHOLD_CM,
            hours_until_threshold: 0,
            predicted_at: new Date().toISOString(),
            fill_rate_cm_per_hour: Math.round(slope * 1000) / 1000,
            r_squared: Math.round(r2 * 1000) / 1000,
            confidence,
            model: "linear_regression",
            data_points_used: dataPointCount,
            note: "Threshold already reached — emptying recommended now.",
            projection_points: projectionPoints
        };
    }

    return {
        threshold_cm: CLEANER_THRESHOLD_CM,
        hours_until_threshold: Math.round(hoursFromNow * 10) / 10,
        predicted_at: new Date(Date.now() + hoursFromNow * 3600000).toISOString(),
        fill_rate_cm_per_hour: Math.round(slope * 1000) / 1000,
        r_squared: Math.round(r2 * 1000) / 1000,
        confidence,
        model: "linear_regression",
        data_points_used: dataPointCount,
        projection_points: projectionPoints
    };
}


// ════════════════════════════════════════════════════════════════
// MAIN
// ════════════════════════════════════════════════════════════════

const rows = msg.payload;
const binId = msg.binId;

if (!rows || rows.length === 0) {
    msg.payload = { bin_id: binId, error: "no_data", message: "No fill readings found." };
    msg.statusCode = 404;
    return msg;
}

// Work in chronological order (oldest first) for regression & event detection
const ordered = [...rows].reverse();

// Detect emptying events across all readings
const emptyingEvents = detectEmptyingEvents(ordered);

// ── Current state from latest reading ────────────────────────────
const latest = rows[0];   // newest-first, so index 0 is latest
const latestDist = parseFloat(latest.distance_cm);
const { status: currentStatus, filledPct } = categorize(latestDist);

// ── Check if we're in a post-emptying state ───────────────────────
const postEmptying = isPostEmptyingState(latestDist, emptyingEvents, ordered);

if (postEmptying) {
    // Determine the specific sub-reason
    let subReason;
    if (latestDist === null || isNaN(latestDist) || latestDist > MAX_DIST) {
        subReason = "out_of_range_reading";
    } else if (latestDist >= BAG_BLOAT_RANGE_MIN) {
        subReason = "possible_bag_bloat_or_bump";
    } else if (latestDist < LID_ON_MAX_CM) {
        subReason = "lid_closed_or_bag_nearby";
    } else {
        subReason = "empty_after_service";
    }

    msg.payload = {
        bin_id: binId,
        current_status: "EMPTY",
        current_distance_cm: isNaN(latestDist) ? null : latestDist,
        filled_pct: 0,
        last_reading_at: latest.recorded_at,
        post_emptying_state: true,
        post_emptying_reason: subReason,
        note: "Bin was recently emptied. Fill level readings unreliable until new waste accumulates.",
        prediction: null,
        emptying_events: emptyingEvents,
        data_points_used: rows.length
    };
    msg.statusCode = 200;
    return msg;
}

// ── Check for UNKNOWN (lid/bag) outside post-emptying context ─────
if (currentStatus === "UNKNOWN") {
    const lastValid = rows.find(r => {
        const d = parseFloat(r.distance_cm);
        return d >= LID_ON_MAX_CM && d <= MAX_DIST;
    });

    msg.payload = {
        bin_id: binId,
        current_status: "UNKNOWN",
        current_distance_cm: isNaN(latestDist) ? null : latestDist,
        filled_pct: 0,
        last_reading_at: latest.recorded_at,
        note: "Distance < 12 cm — sensor blocked by swing lid or bag placed nearby.",
        prediction: null,
        last_valid_reading: lastValid ? {
            distance_cm: parseFloat(lastValid.distance_cm),
            recorded_at: lastValid.recorded_at,
            ...categorize(parseFloat(lastValid.distance_cm))
        } : null,
        emptying_events: emptyingEvents,
        data_points_used: rows.length
    };
    msg.statusCode = 200;
    return msg;
}

// ── Normal state: build regression for prediction ─────────────────

// Only use readings from AFTER the last emptying event (if any)
// so we don't regress across an emptying boundary
let regressionReadings = ordered;
if (emptyingEvents.length > 0) {
    const lastEventIndex = emptyingEvents[emptyingEvents.length - 1].index;
    regressionReadings = ordered.slice(lastEventIndex + 1);
}

// Filter to valid measurable readings only
regressionReadings = regressionReadings.filter(r => {
    const d = parseFloat(r.distance_cm);
    return !isNaN(d) && d >= LID_ON_MAX_CM && d <= MAX_DIST;
});

let prediction = null;

if (regressionReadings.length >= 2) {
    const t0 = new Date(regressionReadings[0].recorded_at).getTime();
    const points = regressionReadings.map(r => ({
        x: (new Date(r.recorded_at).getTime() - t0) / 3600000,
        y: parseFloat(r.distance_cm)
    }));

    const regression = linearRegression(points);
    prediction = buildPrediction(regression, t0, regressionReadings.length);
}

// ── Final response ────────────────────────────────────────────────
msg.payload = {
    bin_id: binId,
    current_status: currentStatus,
    current_distance_cm: latestDist,
    filled_pct: filledPct,
    last_reading_at: latest.recorded_at,
    post_emptying_state: false,
    prediction,
    emptying_events: emptyingEvents,
    data_points_used: rows.length
};
msg.statusCode = 200;
return msg;
